class Solution:
    def numberOfWays(self, corridor: str) -> int:
        MOD = 1_000_000_007
        n = len(corridor)
        slots = list(range(1, n))
        count = 0
        # Exhaustively try every subset of the possible extra divider
        # positions and check each resulting section directly -- a
        # deliberately brute-force mechanism, independent of the
        # gap-product formula used by the optimal solution.
        total = 1 << len(slots)
        for mask in range(total):
            dividers = [0]
            for j, pos in enumerate(slots):
                if mask & (1 << j):
                    dividers.append(pos)
            dividers.append(n)
            valid = True
            for a, b in zip(dividers, dividers[1:]):
                if corridor[a:b].count('S') != 2:
                    valid = False
                    break
            if valid:
                count += 1
        return count % MOD

