class Solution:
    def numberOfWays(self, corridor: str) -> int:
        MOD = 1_000_000_007
        seats = [i for i, ch in enumerate(corridor) if ch == 'S']
        if len(seats) == 0 or len(seats) % 2 != 0:
            return 0
        ans = 1
        for i in range(2, len(seats), 2):
            ans = (ans * (seats[i] - seats[i - 1])) % MOD
        return ans

